func messageClass(message NotificationSettingsMessage) string {
	if message.Kind == "error" {
		return "notice notice--error"
	}

	return "notice notice--success"
}

func statusChipClass(status string) string {
	if status == "enabled" || status == "delivered" {
		return "chip chip--ok"
	}

	return "chip chip--debug"
}

func destinationOptionValue(provider string, id string) string {
	return provider + ":" + id
}

func providerCountLabel() string {
	return "8 providers"
}

func destinationCount(view settingsapp.ProjectSettingsView) int {
	return len(view.TelegramDestinations) + len(view.WebhookDestinations) + len(view.EmailDestinations) + len(view.DiscordDestinations) + len(view.GoogleChatDestinations) + len(view.NtfyDestinations) + len(view.TeamsDestinations) + len(view.ZulipDestinations)
}

func telegramDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.TelegramDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func webhookDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.WebhookDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func emailDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.EmailDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func discordDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.DiscordDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func googleChatDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.GoogleChatDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func ntfyDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.NtfyDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func teamsDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.TeamsDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func zulipDestinationCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.ZulipDestinations) == 1 {
		return "1 destination"
	}

	return "destinations"
}

func alertCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.IssueOpenedAlerts) == 1 {
		return "1 rule"
	}

	return "rules"
}

func deliveryCountLabel(view settingsapp.ProjectSettingsView) string {
	if len(view.DeliveryIntents) == 1 {
		return "1 delivery"
	}

	return "deliveries"
}

func deliveryAttemptText(delivery settingsapp.DeliveryIntentView) string {
	return fmt.Sprintf("%d", delivery.Attempts)
}

func retentionDaysText(days int) string {
	return fmt.Sprintf("%dd", days)
}

func quotaLimitText(limit int) string {
	if limit <= 0 {
		return "off"
	}

	return fmt.Sprintf("%d", limit)
}

func quotaStatusText(enabled bool) string {
	if enabled {
		return "enabled"
	}

	return "disabled"
}

func rateLimitPerMinuteText(limit int) string {
	if limit <= 0 {
		return "off"
	}

	return fmt.Sprintf("%d/min", limit)
}

func rateLimitWindowText(limit int, seconds int) string {
	if limit <= 0 || seconds <= 0 {
		return "not enforced"
	}

	return fmt.Sprintf("%d requests / %ds", limit, seconds)
}

func shortKeyText(publicKey string) string {
	if len(publicKey) <= 8 {
		return publicKey
	}

	return publicKey[:8]
}

func alertStatusAction(alert settingsapp.IssueOpenedAlertView) string {
	if alert.Status == "enabled" {
		return "/settings/notifications/issue-opened-alerts/" + alert.ID + "/disable"
	}

	return "/settings/notifications/issue-opened-alerts/" + alert.ID + "/enable"
}

func alertStatusButtonText(alert settingsapp.IssueOpenedAlertView) string {
	if alert.Status == "enabled" {
		return "Disable"
	}

	return "Enable"
}

